import { readFile, writeFile } from "node:fs/promises";
import { resolve } from "node:path";

const root = "/Users/sggg/Agent/wordbox";
const inputFiles = ["storage.js", "llm.js", "agents.js", "app.js"];
const outFile = resolve(root, "app.bundle.js");

function stripImports(source) {
  return source.replace(/^\s*import[\s\S]*?;\n/gm, "");
}

function stripExports(source) {
  return source.replace(/\bexport\s+/g, "");
}

const pieces = [];
for (const file of inputFiles) {
  const raw = await readFile(resolve(root, file), "utf8");
  pieces.push(`// ${file}\n${stripExports(stripImports(raw)).trim()}\n`);
}

const banner = `// Generated by build-bundle.mjs. Do not edit directly.\n(() => {\n`;
const footer = `\n})();\n`;

await writeFile(outFile, `${banner}${pieces.join("\n")}${footer}`, "utf8");
